package main

// Compliant: Meaningful comments or removal of empty ones

/*
 * Tax calculation module
 * 
 * Implements standard tax calculations based on
 * current tax brackets and deduction rules.
 */

func calculateTax(income float64) float64 {
    /*
     * Standard tax rate calculation
     * TODO: Implement progressive tax brackets
     */
    return income * 0.2
}

/*
 * Order processing workflow
 *
 * Handles order validation, inventory checks,
 * and payment processing.
 */
func processOrder(order *Order) {
    // Validate order before processing
    validateOrder(order)

    /*
     * Multi-step validation process:
     * 1. Check required fields
     * 2. Verify inventory availability
     * 3. Validate payment information
     */
    checkInventory(order)
    processPayment(order)
}

/*
 * User represents a system user with basic information
 *
 * Fields:
 *   Name  - User's full name
 *   Email - User's email address (must be unique)
 */
type User struct {
    Name  string
    Email string
}

// Alternative: Remove unnecessary comments entirely
func simpleFunction() {
    // Simple implementation without empty comments
    doSomething()
}

// GOOD: Single-line comments when multi-line isn't needed
func anotherFunction() {
    // Process data
    processData()
}
